import java.io.*;
import java.util.*;
import org.apache.commons.text.StringEscapeUtils;

public class SecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Sanitize and encode user input to prevent XSS
        String sanitizedName = StringEscapeUtils.escapeHtml4(name);

        System.out.println("Hello, " + sanitizedName + "!"); // Safely displaying user input

        // The following line will no longer execute as a script
        System.out.println("<script>alert('XSS attack executed!')</script>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
